```go
package lru

import (
    "container/list"
    "sync"
    "time"
)

type entry[K comparable, V any] struct {
    key       K
    value     V
    expiresAt time.Time
}

type Cache[K comparable, V any] struct {
    capacity int
    items    map[K]*list.Element
    evictList *list.List
    mu       sync.RWMutex
    onEvict  func(key K, value V)

    // Metrics
    hits      uint64
    misses    uint64
    evictions uint64
}

type Stats struct {
    Hits      uint64
    Misses    uint64
    Evictions uint64
    Size      int
    Capacity  int
}

func New[K comparable, V any](capacity int) *Cache[K, V] {
    return &Cache[K, V]{
        capacity:  capacity,
        items:     make(map[K]*list.Element),
        evictList: list.New(),
    }
}

func (c *Cache[K, V]) WithEvictionCallback(fn func(K, V)) *Cache[K, V] {
    c.onEvict = fn
    return c
}

func (c *Cache[K, V]) Get(key K) (V, bool) {
    c.mu.Lock()
    defer c.mu.Unlock()

    var zero V
    elem, ok := c.items[key]
    if !ok {
        c.misses++
        return zero, false
    }

    ent := elem.Value.(*entry[K, V])

    // Check TTL
    if !ent.expiresAt.IsZero() && time.Now().After(ent.expiresAt) {
        c.removeElement(elem)
        c.misses++
        return zero, false
    }

    c.evictList.MoveToFront(elem)
    c.hits++
    return ent.value, true
}

func (c *Cache[K, V]) Set(key K, value V) {
    c.SetWithTTL(key, value, 0)
}

func (c *Cache[K, V]) SetWithTTL(key K, value V, ttl time.Duration) {
    c.mu.Lock()
    defer c.mu.Unlock()

    var expiresAt time.Time
    if ttl > 0 {
        expiresAt = time.Now().Add(ttl)
    }

    if elem, ok := c.items[key]; ok {
        c.evictList.MoveToFront(elem)
        elem.Value.(*entry[K, V]).value = value
        elem.Value.(*entry[K, V]).expiresAt = expiresAt
        return
    }

    ent := &entry[K, V]{
        key:       key,
        value:     value,
        expiresAt: expiresAt,
    }
    elem := c.evictList.PushFront(ent)
    c.items[key] = elem

    if c.evictList.Len() > c.capacity {
        c.removeOldest()
    }
}

func (c *Cache[K, V]) Delete(key K) bool {
    c.mu.Lock()
    defer c.mu.Unlock()

    elem, ok := c.items[key]
    if !ok {
        return false
    }

    c.removeElement(elem)
    return true
}

func (c *Cache[K, V]) Len() int {
    c.mu.RLock()
    defer c.mu.RUnlock()
    return c.evictList.Len()
}

func (c *Cache[K, V]) Clear() {
    c.mu.Lock()
    defer c.mu.Unlock()

    for key, elem := range c.items {
        if c.onEvict != nil {
            ent := elem.Value.(*entry[K, V])
            c.onEvict(key, ent.value)
        }
        delete(c.items, key)
    }
    c.evictList.Init()
}

func (c *Cache[K, V]) Stats() Stats {
    c.mu.RLock()
    defer c.mu.RUnlock()

    return Stats{
        Hits:      c.hits,
        Misses:    c.misses,
        Evictions: c.evictions,
        Size:      c.evictList.Len(),
        Capacity:  c.capacity,
    }
}

func (c *Cache[K, V]) removeOldest() {
    elem := c.evictList.Back()
    if elem != nil {
        c.removeElement(elem)
    }
}

func (c *Cache[K, V]) removeElement(elem *list.Element) {
    c.evictList.Remove(elem)
    ent := elem.Value.(*entry[K, V])
    delete(c.items, ent.key)
    c.evictions++

    if c.onEvict != nil {
        c.onEvict(ent.key, ent.value)
    }
}
```

Usage example:

```go
cache := lru.New[string, int](100)

cache.Set("key1", 42)
cache.SetWithTTL("key2", 100, 5*time.Minute)

if val, ok := cache.Get("key1"); ok {
    fmt.Println(val)
}

stats := cache.Stats()
fmt.Printf("Hits: %d, Misses: %d, Evictions: %d, Hit Rate: %.2f%%\n",
    stats.Hits, stats.Misses, stats.Evictions,
    float64(stats.Hits)/float64(stats.Hits+stats.Misses)*100)
```

The metrics are tracked atomically within the mutex-protected operations, so they're thread-safe. Hit rate calculation is left to the caller since it's a simple derived metric.
